  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  readEntityName,
  9→  searchEntitiesByEmbedding,
 10→  type ConversationEntity,
 11→  type RankedEntity,
 12→  type WorkspaceDecisionSummary,
 13→  type WorkspaceProjectSummary,
 14→  type WorkspaceQuestionSummary,
 15→} from "../graph/queries";
 16→import { listWorkspaceOpenObservations } from "../observation/queries";
 17→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 18→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→import { loadActiveLearnings } from "../learning/loader";
 21→import { formatLearningsSection } from "../learning/formatter";
 22→
 23→export type DiscussedEntityContext = {
 24→  kind: string;
 25→  name: string;
 26→  status?: string;
 27→};
 28→
 29→export type ChatContext = {
 30→  conversationEntities: ConversationEntity[];
 31→  relevantEntities?: RankedEntity[];
 32→  workspaceDescription?: string;
 33→  workspaceSummary: {
 34→    projects: WorkspaceProjectSummary[];
 35→    recentDecisions: WorkspaceDecisionSummary[];
 36→    openQuestions: WorkspaceQuestionSummary[];
 37→    openObservations: ObservationSummary[];
 38→    pendingSuggestions: SuggestionSummary[];
 39→  };
 40→  onboardingSummary?: string;
 41→  discussedEntity?: DiscussedEntityContext;
 42→  learningsSection?: string;
 43→};
 44→
 45→type ChatContextLoaders = {
 46→  listConversationEntities: typeof listConversationEntities;
 47→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 48→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 49→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 50→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 51→  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
 52→  loadOnboardingSummary: typeof loadOnboardingSummary;
 53→};
 54→
 55→export async function buildChatContext(input: {
 56→  surreal: Surreal;
 57→  conversationRecord: RecordId<"conversation", string>;
 58→  workspaceRecord: RecordId<"workspace", string>;
 59→  workspaceDescription?: string;
 60→  loaders?: ChatContextLoaders;
 61→  inheritedEntityIds?: RecordId[];
 62→  discussesRecord?: RecordId;
 63→  userMessageEmbedding?: number[];
 64→}): Promise<ChatContext> {
 65→  const loaders = input.loaders ?? {
 66→    listConversationEntities,
 67→    listWorkspaceProjectSummaries,
 68→    listWorkspaceRecentDecisions,
 69→    listWorkspaceOpenQuestions,
 70→    listWorkspaceOpenObservations,
 71→    listWorkspacePendingSuggestions,
 72→    loadOnboardingSummary,
 73→  };
 74→
 75→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary, learningsResult] = await Promise.all([
 76→    loaders.listConversationEntities({
 77→      surreal: input.surreal,
 78→      conversationRecord: input.conversationRecord,
 79→      workspaceRecord: input.workspaceRecord,
 80→      limit: 60,
 81→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 82→        ? { inheritedEntityIds: input.inheritedEntityIds }
 83→        : {}),
 84→    }),
 85→    loaders.listWorkspaceProjectSummaries({
 86→      surreal: input.surreal,
 87→      workspaceRecord: input.workspaceRecord,
 88→      limit: 20,
 89→    }),
 90→    loaders.listWorkspaceRecentDecisions({
 91→      surreal: input.surreal,
 92→      workspaceRecord: input.workspaceRecord,
 93→      limit: 12,
 94→    }),
 95→    loaders.listWorkspaceOpenQuestions({
 96→      surreal: input.surreal,
 97→      workspaceRecord: input.workspaceRecord,
 98→      limit: 12,
 99→    }),
100→    loaders.listWorkspaceOpenObservations({
101→      surreal: input.surreal,
102→      workspaceRecord: input.workspaceRecord,
103→      limit: 10,
104→    }),
105→    loaders.listWorkspacePendingSuggestions({
106→      surreal: input.surreal,
107→      workspaceRecord: input.workspaceRecord,
108→      limit: 10,
109→    }),
110→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
111→    loadActiveLearnings({
112→      surreal: input.surreal,
113→      workspaceId: input.workspaceRecord.id as string,
114→      agentType: "chat_agent",
115→      ...(input.workspaceDescription ? { contextEmbedding: undefined } : {}),
116→    }),
117→  ]);
118→
119→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
120→  let relevantEntities: RankedEntity[] | undefined;
121→  if (input.userMessageEmbedding) {
122→    const queryEmbedding = input.userMessageEmbedding;
123→    const conversationEntityIds = new Set(
124→      conversationEntities.map((e) => e.id),
125→    );
126→    const ranked = await searchEntitiesByEmbedding({
127→      surreal: input.surreal,
128→      workspaceRecord: input.workspaceRecord,
129→      queryEmbedding,
130→      limit: 15,
131→    });
132→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
133→    if (filtered.length > 0) {
134→      relevantEntities = filtered.slice(0, 10);
135→    }
136→  }
137→
138→  let discussedEntity: DiscussedEntityContext | undefined;
139→  if (input.discussesRecord) {
140→    const entityRecord = input.discussesRecord as GraphEntityRecord;
141→    const name = await readEntityName(input.surreal, entityRecord);
142→    if (name) {
143→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
144→      discussedEntity = {
145→        kind: entityRecord.table.name,
146→        name,
147→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
148→      };
149→    }
150→  }
151→
152→  const learningsSection = formatLearningsSection(learningsResult.learnings);
153→
154→  return {
155→    conversationEntities,
156→    relevantEntities,
157→    ...(input.workspaceDescription ? { workspaceDescription: input.workspaceDescription } : {}),
158→    workspaceSummary: {
159→      projects,
160→      recentDecisions,
161→      openQuestions,
162→      openObservations,
163→      pendingSuggestions,
164→    },
165→    onboardingSummary,
166→    discussedEntity,
167→    ...(learningsSection ? { learningsSection } : {}),
168→  };
169→}
170→
171→function formatConversationEntities(entities: ConversationEntity[]): string {
172→  if (entities.length === 0) {
173→    return "- none";
174→  }
175→
176→  return entities
177→    .slice(0, 20)
178→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
179→    .join("\n");
180→}
181→
182→
183→function formatRelevantEntities(entities: RankedEntity[]): string {
184→  return entities
185→    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
186→    .join("\n");
187→}
188→
189→function formatWorkspaceSummary(context: ChatContext): string {
190→  const { projects, recentDecisions, openQuestions, openObservations, pendingSuggestions } = context.workspaceSummary;
191→
192→  const lines: string[] = [];
193→
194→  // Projects: keep names since they're needed for routing
195→  if (projects.length === 0) {
196→    lines.push("- Projects: none");
197→  } else {
198→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
199→  }
200→
201→  // Decisions: count by status
202→  if (recentDecisions.length === 0) {
203→    lines.push("- Decisions: none");
204→  } else {
205→    const statusCounts = new Map<string, number>();
206→    for (const d of recentDecisions) {
207→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
208→    }
209→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
210→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
211→  }
212→
213→  // Questions: just count
214→  lines.push(`- Open questions: ${openQuestions.length}`);
215→
216→  // Observations: count by severity
217→  if (openObservations.length === 0) {
218→    lines.push("- Observations: none");
219→  } else {
220→    const severityCounts = new Map<string, number>();
221→    for (const o of openObservations) {
222→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
223→    }
224→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
225→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
226→  }
227→
228→  // Suggestions: count by category
229→  if (pendingSuggestions.length === 0) {
230→    lines.push("- Suggestions: none");
231→  } else {
232→    const categoryCounts = new Map<string, number>();
233→    for (const s of pendingSuggestions) {
234→      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
235→    }
236→    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
237→    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
238→  }
239→
240→  return lines.join("\n");
241→}
242→
243→type SystemPromptOptions = {
244→  isOnboarding?: boolean;
245→  onboardingState?: OnboardingState;
246→  workspaceName?: string;
247→};
248→
249→export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
250→  const sections: string[] = [
251→    "You are the Chat agent for Brain — an agent-native business operating system.",
252→    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
253→    "",
254→    "## Core Behavior: Act, Don't Describe",
255→    "When the user describes work to be done, **use your tools to create entities in the graph immediately**. Do NOT:",
256→    "- List what you *could* do and ask for permission",
257→    "- Write prose descriptions of features/tasks without creating them",
258→    "- Ask \"would you like me to help break these down?\" — just break them down",
259→    "- Explain that \"the data model already has X\" — if the user describes structure, they mean THEIR domain, not Brain's internals",
260→    "- Suggest generic next steps without executing them",
261→    "",
262→    "When the user says \"yes\" to creating work items, dispatch the PM agent or use create_work_item. When they describe a decision, use create_provisional_decision. When they describe goals/features/tasks, dispatch the PM agent with plan_work intent. Your value is in *doing*, not *describing what you could do*.",
263→    "",
264→    "## Domain Separation",
265→    "The user's business — whatever they are building, planning, or discussing — is NOT Brain itself.",
266→    "Even if the user's domain uses identical terms (entities, graphs, tasks, features, hierarchy), treat ALL user input as business content to capture in the graph.",
267→    "When the user says \"I want entities: X → Y → Z\" or describes a hierarchy, they are describing THEIR domain model — dispatch the PM agent to plan it as work items.",
268→    "Never explain Brain's data model, architecture, or current entity types unless the user explicitly asks \"how does Brain work?\" or similar.",
269→    "",
270→    "## What This System Is",
271→    "Brain replaces the human as shared memory between agents. Instead of re-explaining context every session, agents read from and write to a knowledge graph. The graph captures every decision, constraint, task, and relationship — so any agent (or the human) can query it and get full context instantly.",
272→    "",
273→    "The user sets strategy and constraints. Agents execute. The graph is shared memory. The feed is where the user governs (reviews pending decisions, resolves conflicts, approves work).",
274→    "",
275→    "## Data Model (Internal Reference)",
276→    "This section describes how YOU store data. Do not explain this to the user — just use it to pick the right tools.",
277→    "The graph has these entity types:",
278→    "",
279→    "**Work hierarchy:** Project → Feature → Task",
280→    "- **Project**: a named initiative with status, description, and embedding. Linked to workspace via `has_project` edge.",
281→    "- **Feature**: a capability or deliverable within a project. Linked via `has_feature` edge.",
282→    "- **Task**: an actionable work item. Can belong to a feature (`has_task`) or directly to a project (`belongs_to`). Has status (open/done/etc), priority, category, optional owner and deadline.",
283→    "",
284→    "**Cross-cutting entities** (can attach to any level via `belongs_to`):",
285→    "- **Decision**: a choice that was made. Status lifecycle: extracted → proposed → provisional → confirmed → superseded. Can conflict with other decisions (`conflicts_with` edge).",
286→    "- **Question**: an open question requiring a choice. Not for informational queries — only for pending decisions.",
287→    "- **Observation**: a lightweight signal (info/warning/conflict) written by agents. Lifecycle: open → acknowledged → resolved. Used for cross-project intelligence (\"this billing decision conflicts with your auth rate limiting\").",
288→    "- **Suggestion**: a proactive agent-to-human proposal. Categories: optimization, risk, opportunity, conflict, missing, pivot. Lifecycle: pending → accepted/dismissed/deferred → converted. Built on accumulated observations via `suggestion_evidence` edges. Use `create_suggestion` for actionable proposals with rationale.",
289→    "",
290→    "**Other entities:** Person (with ownership edges), Meeting, Document, Git Commit, Pull Request.",
291→    "",
292→    "**Key relationships (graph edges):**",
293→    "- `has_project`: workspace → project",
294→    "- `has_feature`: project → feature",
295→    "- `has_task`: feature → task",
296→    "- `belongs_to`: task|decision|question → feature|project",
297→    "- `depends_on`: task|feature → task|feature (blocks/needs/soft)",
298→    "- `conflicts_with`: decision|feature ↔ decision|feature",
299→    "- `owns`: person → task|project|feature",
300→    "- `observes`: observation → project|feature|task|decision|question",
301→    "- `suggests_for`: suggestion → project|feature|task|question|decision",
302→    "- `suggestion_evidence`: suggestion → observation|decision|task|feature|project|question|person|workspace",
303→    "- `superseded_by`: decision → decision",
304→    "",
305→    "## How Data Enters the Graph",
306→    "1. **Agent tools** (primary path): you and other agents write structured data (decisions, observations, work items) directly to the graph via tools. When the user mentions entities, projects, tasks, or decisions, use your tools to create them — there is no automatic extraction.",
307→    "2. **User acceptance**: when you suggest work items, the user can accept them into the graph with one click.",
308→    "",
309→    "When the user describes work, use your tools to create the actual entities.",
310→    "",
311→    "## Architecture: Graph as Communication Bus",
312→    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
313→    "- Each agent reads the graph for context it needs.",
314→    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
315→    "- Subsequent agents read the graph and see prior agents' work.",
316→    "- You synthesize the user-facing response from graph state and tool results.",
317→    "",
318→    "Never assume data from other workspaces.",
319→    "",
320→  ];
321→
322→  // Onboarding mode instructions
323→  if (options?.isOnboarding && options.onboardingState !== "complete") {
324→    if (options.onboardingState === "summary_pending") {
325→      sections.push(
326→        "## Onboarding Mode — Summary",
327→        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
328→        "",
329→        "Current workspace state:",
330→        context.onboardingSummary ?? "No entities captured yet.",
331→        "",
332→      );
333→    } else {
334→      const workspaceName = options.workspaceName;
335→      const topicList = context.workspaceDescription
336→        ? "projects and product areas, people, decisions, tools, bottlenecks."
337→        : "business/venture, projects, people, decisions, tools, bottlenecks.";
338→      sections.push(
339→        "## Onboarding Mode",
340→        "You are onboarding a newly created workspace.",
341→        ...(context.workspaceDescription
342→          ? [
343→            ...(workspaceName ? [`The workspace is named "${workspaceName}".`] : []),
344→            `The workspace is described as: "${context.workspaceDescription}"`,
345→            "Do not ask what the business is — focus on discovering projects and product areas within it.",
346→            "",
347→            "## Workspace ≠ Project — Classification Rules",
348→            ...(workspaceName ? [`"${workspaceName}" is the workspace (the business/brand). NEVER create a project with the same name as the workspace.`] : []),
349→            "What the user describes next are PROJECTS within this workspace — named product areas, modules, or workstreams.",
350→            "When the user sends a heading (e.g. \"DASHBOARD\") with a description and bullet points:",
351→            "- The heading is a **Project** — create it as a project",
352→            "- Bullet points describing capabilities are **Features** within that project",
353→            "- Bullet points with action verbs (implement, build, fix) are **Tasks**",
354→            "Do NOT nest the user's described structure one level too deep (e.g. making the workspace name a project and demoting projects to features).",
355→          ]
356→          : [
357→            "**CRITICAL: The workspace has no description yet.** The user's first messages describe the business or domain — they are NOT naming specific projects.",
358→            "You MUST first understand the business context before creating any project entities.",
359→            "Do NOT dispatch PM agent with plan_work intent until the user has explicitly named specific projects or product areas as distinct from the business itself.",
